{
  "integration_assessment": {
    "component_interactions": [
      {
        "from": "KYC Verification Service",
        "to": "Onfido API",
        "status": "risk",
        "issue": "Synchronous blocking call with no circuit breaker or fallback. Onfido's SLA (99.9%) is lower than the team's internal SLA (99.95%), making the internal SLA mathematically unachievable. At best, the KYC service inherits Onfido's 99.9% availability, leaving a 0.05% gap (≈26 minutes/year of additional downtime budget that doesn't exist)."
      },
      {
        "from": "User Registration Flow",
        "to": "KYC Verification Service",
        "status": "risk",
        "issue": "Registration is hard-blocked on KYC completion. Any Onfido degradation directly blocks new user acquisition with no graceful alternative. Users see a 503 and have no indication of when to retry."
      }
    ],
    "contract_compliance": "Onfido integration appears functional but the coupling is too tight for production. The service has no contract validation on Onfido responses (e.g., schema drift, unexpected status codes). If Onfido changes payload shape, failures will be opaque.",
    "data_flow_integrity": "Linear synchronous flow: User → Registration → KYC Service → Onfido → response → registration complete/fail. No async path, no queue, no eventual-consistency option. Data flow is correct but fragile."
  },

  "observability_review": {
    "logging": {
      "coverage": "adequate",
      "gaps": [
        "No mention of logging Onfido response bodies or error codes on failure — critical for debugging provider-side issues at 3am",
        "No correlation ID / request tracing between registration request and Onfido call"
      ]
    },
    "metrics": {
      "coverage": "partial — kyc_checks_total and kyc_duration_histogram are good starts",
      "gaps": [
        "No error-rate metric broken down by Onfido error type (timeout vs 5xx vs 4xx vs network error)",
        "No metric tracking consecutive Onfido failures (needed for circuit breaker / alerting on sustained outages)",
        "No metric for user-facing registration failures caused by KYC dependency",
        "No Onfido latency percentile alerting threshold defined"
      ]
    },
    "tracing": {
      "coverage": "not mentioned",
      "gaps": [
        "No distributed tracing spans for the Onfido call — cannot correlate upstream registration latency with downstream provider latency",
        "No trace context propagation from registration service to KYC service"
      ]
    },
    "debugging_capability": "Moderate. Structured JSON logging and basic metrics exist, but an on-call engineer cannot currently distinguish between 'Onfido is down' and 'our service is broken' without manually checking the /health endpoint. Need Onfido-specific error classification in logs and metrics."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Onfido full outage (within their 0.1% downtime budget)",
        "handling": "unhandled",
        "recommendation": "MUST-HAVE: Implement a circuit breaker (e.g., 5 failures in 30s → open for 60s). When open, return a 'pending_verification' status and allow registration to proceed with limited capabilities. Queue the KYC check for async retry. This is the single most critical gap."
      },
      {
        "scenario": "Onfido latency degradation (p99 approaching 3s, some requests >5s)",
        "handling": "partial",
        "recommendation": "5s timeout exists but no adaptive behavior. Under sustained latency, all registration requests will pile up waiting 5s each. Add connection pool limits and consider reducing timeout to 3.5s (aligned with Onfido's p99 SLA) with a fast-fail to a degraded path."
      },
      {
        "scenario": "Onfido rate limiting or quota exhaustion",
        "handling": "unhandled",
        "recommendation": "Add handling for HTTP 429 responses. Implement exponential backoff for async retries. Alert when approaching quota limits."
      },
      {
        "scenario": "Onfido returns unexpected/malformed response",
        "handling": "unhandled",
        "recommendation": "Add response schema validation. Log full response on parse failure. Return a safe default (pending_verification) rather than crashing."
      },
      {
        "scenario": "Cascading failure under load — Onfido slow, thread pool exhaustion in KYC service",
        "handling": "unhandled",
        "recommendation": "Without a circuit breaker, slow Onfido responses will consume all available connections/threads. Add bulkhead isolation: cap concurrent Onfido calls (e.g., 20) so the KYC service can still serve health checks and other endpoints."
      },
      {
        "scenario": "Network partition between KYC service and Onfido",
        "handling": "partial",
        "recommendation": "5s timeout covers this partially, but DNS resolution failures and TLS handshake timeouts should have separate, shorter timeouts (e.g., connect timeout 2s, read timeout 3s)."
      }
    ],
    "retry_config": "No retry logic mentioned. MUST-HAVE for transient failures: 1 retry with jitter for 5xx/timeout, no retry for 4xx. Without retries, every transient Onfido blip becomes a user-facing registration failure.",
    "timeout_config": "5s total timeout exists. Acceptable as a ceiling but should be split into connect timeout (2s) and read timeout (3s). Current single timeout cannot distinguish network issues from slow processing.",
    "circuit_breakers": "NONE. This is the critical gap. A circuit breaker is required to meet the 99.95% SLA when depending on a 99.9% upstream. The circuit breaker enables the degraded path that makes the math work.",
    "graceful_degradation": "NONE. Binary pass/fail with no middle ground. The service needs a 'pending_verification' state where users can register but are gated from transacting until KYC completes asynchronously. This is standard practice in fintech onboarding."
  },

  "operational_readiness": {
    "deployment_ready": false,
    "rollback_capable": true,
    "rollback_plan": "Redeploy previous container image. Acceptable for the service itself, but note: if a rollback is needed due to Onfido integration issues, redeploying won't fix the root cause. Need runbook for Onfido-specific incidents.",
    "monitoring_coverage": "Partial. /health endpoint checking Onfido reachability is good. Missing: alerting rules on kyc_duration_histogram p99 > 3s, alert on kyc error rate > 1%, alert on consecutive health check failures, dashboard for Onfido dependency health.",
    "on_call_documentation": "Not mentioned. MUST-HAVE: Runbook covering (1) Onfido is down — what to do, who to contact at Onfido, escalation path, (2) KYC service high error rate — diagnostic steps, (3) how to manually approve/queue KYC checks if provider is down for extended period.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": ["Async retry queue (e.g., SQS/RabbitMQ) for deferred KYC checks when circuit breaker is open"],
      "new_queues_topics": ["kyc-pending-verification-retry queue for async KYC processing"],
      "config_changes": ["Circuit breaker thresholds", "Retry policy configuration", "Split connect/read timeouts"],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "No database migrations mentioned. However, implementing the recommended 'pending_verification' state will likely require a new KYC status column or state machine — plan for this."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "integration_risk",
      "issue": "Onfido SLA (99.9%) is lower than internal SLA (99.95%) with no mitigation",
      "reason": "The KYC service synchronously depends on Onfido with no circuit breaker, no fallback, and no degraded mode. It is mathematically impossible to meet the 99.95% internal SLA when the critical-path dependency only guarantees 99.9%. The 0.05% gap equals ~26 minutes/year of unbudgeted downtime. A circuit breaker with async fallback queue is required to decouple availability from the provider's SLA. This is an architectural gap — the team needs to decide on the degraded-mode contract (e.g., 'pending_verification' state) before this can ship.",
      "routed_to": "MJ"
    },
    {
      "type": "integration_risk",
      "issue": "No graceful degradation path blocks user acquisition during provider outages",
      "reason": "When Onfido is unavailable, 100% of new user registrations fail with 503. For a fintech platform where user acquisition is revenue-critical, this blast radius is unacceptable. The team needs MJ to design the async verification flow and define what capabilities a user in 'pending_verification' state should have.",
      "routed_to": "MJ"
    }
  ],

  "confidence": {
    "level": 60,
    "high_confidence_areas": [
      "SLA math: 99.9% upstream cannot support 99.95% downstream without decoupling — this is arithmetic, not opinion",
      "Missing circuit breaker is a critical gap for any synchronous external dependency",
      "Observability gaps are identifiable from the stated setup"
    ],
    "low_confidence_areas": [
      "Actual Onfido error response formats and edge cases — would need to review integration code",
      "Thread/connection pool configuration and cascading failure risk — need to see service framework config",
      "Whether a 'pending_verification' state is acceptable under the platform's regulatory requirements — compliance team input needed"
    ],
    "assumptions": [
      "No code was provided; assessment is based on the described architecture and configuration",
      "Onfido is the sole KYC provider with no secondary/backup provider",
      "The platform's regulatory environment permits deferred verification (async KYC) — if not, the degraded mode design changes significantly",
      "The 99.95% SLA applies to the registration flow, not just the KYC service in isolation"
    ]
  }
}

